solution:
fn main() {
    let vec0 = vec![22, 44, 66];

    let vec1 = fill_vec(vec0.clone());

    println!("{} has length {}, with contents: {:?}", "vec0", vec0.len(), vec0);
    println!("{} has length {}, with contents: {:?}", "vec1", vec1.len(), vec1);
}

fn fill_vec(mut vec: Vec<i32>) -> Vec<i32> {
    vec.push(88);
    vec
}
